import{Toast,Modal,restUrl,listen}from"jui";import{t}from"vanilla-signal-i18n";import{createQuery}from"../../../public/javascript/es/vanilla-query.js";const langs={zh:{Login:"登录",username:"用户名",password:"密码",Cancel:"取消","Enter Username Please":"请输入用户名","Enter Password Please":"请输入密码","Username Required":"用户名不能为空","Password Required":"密码不能为空","Login Success":"登录成功"}},ts=e=>t(e,langs),performLogin=async(e,s)=>{const r=await fetch(restUrl+"/api/v1/auth/login",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({username:e,password:s})});if(!r.ok)throw new Error(`HTTP error! status: ${r.status}`);return r.json()},createLoginMutation=e=>createQuery({queryKey:["login",e.username],queryFn:async()=>await performLogin(e.username,e.password),enabled:!1,cache:!1,retry:0,throwErrors:!0}),__loginModal=new Modal({title:ts("Login"),confirmText:ts("Login"),cancelText:ts("Cancel"),escClose:!0,fields:[{label:ts("username"),type:"text",name:"username",id:"username",placeholder:ts("Enter Username Please"),required:!0},{label:ts("password"),type:"password",name:"password",id:"password",placeholder:ts("Enter Password Please"),required:!0}],onSubmit:async e=>{if(e.username.trim())if(e.password.trim())try{const s=createLoginMutation({username:e.username,password:e.password}),r=await s.refetch({force:!0});200===r.code?(Toast.success(ts("Login Success")),setTimeout(()=>{window.location.href="/"},1e3)):Toast.error(r.message)}catch(e){Toast.error(e.message||"Login failed")}else Toast.error(ts("Password Required"));else Toast.error(ts("Username Required"))}});listen(document.body,"click",e=>{e.target.closest('[data-action="login"]')&&__loginModal.show()});